jQuery(document).ready(function(e){e(".add-category-from").on("submit",function(t){t.preventDefault();let a=e("#category_name").val(),o=e("#category_taxonomies").val();e.post(priceTrackerCategoryAjax.ajax_url,{action:"pt_add_category",security:priceTrackerCategoryAjax.category_nonce,name:a,taxonomies:o},function(e){e.success?(alert(e.data.message),location.reload()):alert(e.data.message)})}),e(".delete-category").on("click",function(t){t.preventDefault();let a=e(this).data("category-id");Swal.fire({title:"Are you sure?",text:"This category will be permanently deleted and its items will be deleted as well.",icon:"warning",showCancelButton:!0,confirmButtonColor:"#d33",cancelButtonColor:"#3085d6",confirmButtonText:"Yes, delete it!",cancelButtonText:"Cancel"}).then(t=>{t.isConfirmed&&e.post(priceTrackerCategoryAjax.ajax_url,{action:"pt_delete_category",security:priceTrackerCategoryAjax.category_nonce,id:a},function(e){e.success?Swal.fire({icon:"success",title:"Deleted!",text:e.data.message,timer:2e3,showConfirmButton:!1}).then(()=>{location.reload()}):Swal.fire({icon:"error",title:"Error",text:e.data.message})})})}),e(".edit-category-form").on("submit",function(t){t.preventDefault();let a=e("#edit_category_id").val(),o=e("#edit_category_name").val(),r=e("#edit_category_taxonomies").val();e.post(priceTrackerCategoryAjax.ajax_url,{action:"pt_edit_category",security:priceTrackerCategoryAjax.category_nonce,id:a,name:o,taxonomies:r},function(e){e.success?(alert(e.data.message),location.reload()):alert(e.data.message)})})});
